      "measures_exact_volumes_of_analyte": "Mengukur volume analit yang tepat.",
      "ph_indicator": "Indikator pH",
      "changes_color_to_signal_the_endpoint": "Berubah warna untuk menandakan titik akhir.",
      "wash_bottle": "Botol pencuci",
      "contains_distilled_water_for_rinsing": "Berisi air suling untuk membilas.",
      "goggles_gloves_and_lab_coat": "Kacamata, sarung tangan, dan jas lab",
      "all_three_are_mandatory_goggles_protec": "Ketiganya wajib: kacamata melindungi mata dari percikan, sarung tangan melindungi tangan dari zat korosif, dan jas lab melindungi pakaian dan kulit.",
      "rinse_with_running_water_for_15_min": "Bilas dengan air mengalir selama 15+ menit",
      "water_first_always_the_15_minute_rinse": "Air dulu, selalu! Pembilasan 15 menit sangat penting. Penetral dapat menyebabkan reaksi eksoterm pada kulit.",
      "where_moles_of_acid_moles_of_base": "Di mana mol asam = mol basa",
      "the_equivalence_point_is_the_stoichiom": "Titik ekivalen adalah titik stoikiometri. pH pada ekivalen bergantung pada kekuatan asam/basa — hanya pH 7 untuk asam kuat + basa kuat.",
      "the_exothermic_reaction_can_cause_viol": "Reaksi eksoterm dapat menyebabkan pendidihan hebat dan percikan",
      "when_water_hits_concentrated_acid_the_": "Ketika air mengenai asam pekat, panas yang dilepaskan dapat mendidihkan air seketika, menyebabkan percikan hebat asam panas. Menambahkan asam ke air menyebarkan panas ke volume air yang lebih besar.",
      "above_7": "Di atas 7",
      "at_equivalence_only_the_conjugate_base": "Pada ekivalen, hanya basa konjugat (A⁻) yang tersisa. Basa konjugat asam lemah sendiri adalah basa lemah, membuat larutan bersifat basa (pH > 7).",
      "strong_acid_strong_base_or_weak_acid_s": "Asam kuat + Basa kuat atau Asam lemah + Basa kuat",
      "phenolphthalein_transitions_at_ph_8_2_": "Fenolftalein berubah pada pH 8,2-10,0, yang sesuai dengan pH ekivalen basa dari titrasi asam lemah + basa kuat. Ini juga bekerja untuk AK+BK karena lonjakan tajam melintasi rentangnya.",
      "ammonia_or_acids": "Amonia atau asam",
      "bleach_ammonia_chloramine_gas_toxic_bl": "Pemutih + amonia = gas kloramin (beracun). Pemutih + asam = gas klor (beracun). Keduanya dapat menyebabkan cedera pernapasan serius atau kematian. JANGAN PERNAH menggabungkan pemutih dengan bahan kimia apa pun.",
      "23_45_has_4_significant_figures_the_la": "23,45 memiliki 4 angka penting. Angka terakhir (5) diperkirakan di antara garis skala. Buret akurat hingga ±0,05 mL.",
      "ph_pka": "pH = pKa",
      "at_half_equivalence_ha_a_so_henderson_": "Pada setengah ekivalen, [HA] = [A⁻], sehingga Henderson–Hasselbalch memberikan pH = pKa + log(1) = pKa. Ini adalah pusat wilayah bufer.",
      "when_handling_1m_concentrated_acids_or": "Saat menangani asam atau basa pekat >1M",
      "face_shields_provide_splash_protection": "Pelindung wajah memberikan perlindungan percikan untuk seluruh wajah. Diperlukan untuk zat korosif pekat (>1M), operasi pemanasan, dan prosedur apa pun dengan risiko percikan di luar area mata.",
      "suit_up": "Perlengkapi diri",
